import React, { Component } from 'react';
import { Link} from "react-router-dom";
class SidebarManga extends Component {
    render() {
        return (
            <div className="sidebar-children-manga">
                <img src={this.props.ImageSource} alt=" "/>
                <Link to={"/manga/"+this.props.MangaName+"."+this.props.id}>{this.props.MangaName}</Link>
            </div>
        );
    }
}

export default SidebarManga;
